import subprocess
import os

# Compile all necessary .so files
# First, cythonize all .pyx files
for root, dirs, files in os.walk('sklearn'):
    for f in files:
        if f.endswith('.pyx'):
            pyx_path = os.path.join(root, f)
            c_path = pyx_path.replace('.pyx', '.c')
            if not os.path.exists(c_path) or os.path.getmtime(pyx_path) > os.path.getmtime(c_path):
                print(f'Cythonizing {pyx_path}...')
                result = subprocess.run(['cython', pyx_path, '-o', c_path], 
                                       capture_output=True, text=True, cwd='/testbed')
                if result.returncode != 0:
                    print(f'  Error: {result.stderr[:200]}')
                else:
                    print(f'  Done')
print('All cythonized')
" 2>&1"}

